import React, { useEffect, useState } from "react";
import API from "../../api/api";

const CATEGORIES = [
  { value: "All",                 label: "All" },
  { value: "web-development",     label: "Web Development" },
  { value: "mobile-development",  label: "Mobile Development" },
  { value: "ui-ux-design",        label: "UI/UX Design" },
  { value: "graphic-design",      label: "Graphic Design" },
  { value: "backend-development", label: "Backend Development" },
  { value: "data-science",        label: "Data Science & ML" },
  { value: "devops",              label: "DevOps & Cloud" },
  { value: "content-writing",     label: "Content Writing" },
  { value: "digital-marketing",   label: "Digital Marketing" },
  { value: "video-editing",       label: "Video Editing" },
  { value: "seo",                 label: "SEO" },
  { value: "cybersecurity",       label: "Cybersecurity" },
  { value: "other",               label: "Other" },
];

const formatDate = (dateStr) => {
  if (!dateStr) return "";
  const d = new Date(dateStr);
  return d.toLocaleDateString("en-IN", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  });
};

const FindProjects = () => {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const res = await API.get("/projects");
        setProjects(res.data || []);
      } catch (err) {
        console.error("Error fetching projects:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchProjects();
  }, []);

  const filteredProjects = projects.filter((project) => {
    const matchesSearch = project.title?.toLowerCase().includes(search.toLowerCase());
    const matchesCategory =
      selectedCategory === "All" || project.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const sendProposal = async (projectId) => {
    const bid = prompt("Enter Your Bid Amount (Rs)");
    const message = prompt("Enter Proposal Message");
    if (!bid || !message) return;
    try {
      await API.post("/proposals", { project_id: projectId, bid, message });
      alert("Proposal Sent Successfully!");
    } catch (error) {
      alert("Error sending proposal. Try again.");
    }
  };

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-6xl mx-auto">

        <h1 className="text-3xl font-bold mb-6 text-gray-800">Find Projects</h1>

        {/* SEARCH */}
        <input
          type="text"
          placeholder="Search projects..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full px-4 py-3 border border-gray-300 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-teal-500 mb-4"
        />

        {/* CATEGORY BUTTONS */}
        <div className="flex flex-wrap gap-2 mb-8">
          {CATEGORIES.map((cat) => (
            <button
              key={cat.value}
              onClick={() => setSelectedCategory(cat.value)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition ${
                selectedCategory === cat.value
                  ? "bg-teal-600 text-white shadow"
                  : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              {cat.label}
            </button>
          ))}
        </div>

        {loading && <p className="text-gray-500">Loading projects...</p>}

        {!loading && filteredProjects.length === 0 && (
          <div className="bg-white p-8 rounded-xl shadow text-center text-gray-500">
            No projects found for this category.
          </div>
        )}

        <div className="space-y-6">
          {filteredProjects.map((project) => (
            <div key={project.id} className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm hover:shadow-md transition">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <h3 className="text-xl font-semibold text-gray-800">{project.title}</h3>
                  <p className="text-gray-600 mt-1">{project.description}</p>
                </div>
                <span className="text-green-600 bg-green-100 px-3 py-1 rounded-full text-sm font-medium whitespace-nowrap ml-4">
                  Open
                </span>
              </div>

              {project.skills && (
                <div className="flex flex-wrap gap-2 mb-4">
                  {project.skills.split(",").map((skill, i) => (
                    <span key={i} className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm">
                      {skill.trim()}
                    </span>
                  ))}
                </div>
              )}

              <div className="border-t pt-4 flex justify-between items-center">
                <div className="flex gap-4 text-sm items-center flex-wrap">
                  <span className="font-semibold text-gray-800">Rs {project.budget}</span>
                  {/* DATE FIX */}
                  {project.deadline && (
                    <span className="text-gray-500">Deadline: {formatDate(project.deadline)}</span>
                  )}
                  {project.category && (
                    <span className="bg-teal-50 text-teal-700 px-2 py-0.5 rounded text-xs font-medium">
                      {CATEGORIES.find(c => c.value === project.category)?.label || project.category}
                    </span>
                  )}
                </div>

                <div className="flex items-center gap-4">
                  <span className="text-teal-600 font-medium text-sm">
                    {project.proposalsCount || 0} proposals
                  </span>
                  <button
                    onClick={() => sendProposal(project.id)}
                    className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition"
                  >
                    Apply
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default FindProjects;
